// Simple localStorage-based store for scan history
const STORAGE_KEY = 'ecoscan_records';

export function getRecords() {
  try {
    return JSON.parse(localStorage.getItem(STORAGE_KEY)) || [];
  } catch {
    return [];
  }
}

export function addRecord(category, guidance) {
  const records = getRecords();
  const newRecord = {
    id: Date.now(),
    category,
    guidance,
    timestamp: new Date().toISOString(),
  };
  records.unshift(newRecord); // newest first
  localStorage.setItem(STORAGE_KEY, JSON.stringify(records.slice(0, 500)));
  return newRecord;
}

export function clearRecords() {
  localStorage.removeItem(STORAGE_KEY);
}
